// NQxb_Artifact_List_v1__Normalize_Request
// Canonicalize inbound request for artifact.list operation.
// Accept artifact_type from EITHER:
//   - selector.artifact_type (preferred when present), OR
//   - top-level artifact_type (as sent by Gateway Build_List_Request)
//
// Policy: response-size hardening (Option 2A Clamp)
// - default_limit = 50
// - max_limit = 200
// - missing/invalid/non-positive limit => 50
// - limit > 200 => clamp to 200 (no error)

const raw = $json ?? {};

// Support body-wrapped payloads
const body =
  raw.body && typeof raw.body === "object" && !Array.isArray(raw.body)
    ? raw.body
    : null;

const req = body ?? raw;

// Helper to ensure object
const asObj = (v) =>
  v && typeof v === "object" && !Array.isArray(v) ? v : {};

const selector = asObj(req.selector);

// Extract artifact_type from selector OR top-level
const selectorArtifactType = (selector.artifact_type ?? "").trim();
const topLevelArtifactType = (req.artifact_type ?? "").toString().trim();

const artifact_type =
  selectorArtifactType !== "" ? selectorArtifactType
  : topLevelArtifactType !== "" ? topLevelArtifactType
  : "";

// Other selector fields
const parent_artifact_id = selector.parent_artifact_id ?? null;

// BUG-011: Extract tags_any filter (selector.filters.tags_any)
const filters = selector.filters && typeof selector.filters === "object" ? selector.filters : {};
const tags_any_raw = filters.tags_any ?? filters.tags ?? null;

const DEFAULT_LIMIT = 50;
const MAX_LIMIT = 200;

// Normalize limit with clamp
const rawLimit = selector.limit;
const parsedLimit = parseInt(rawLimit, 10);

const requested_limit =
  Number.isFinite(parsedLimit) && parsedLimit > 0 ? parsedLimit : null;

const applied_limit = Math.min(
  Math.max(requested_limit ?? DEFAULT_LIMIT, 1),
  MAX_LIMIT
);

const was_clamped =
  requested_limit !== null && requested_limit > MAX_LIMIT;

const limit = applied_limit;

const offset = Math.max(parseInt(selector.offset, 10) || 0, 0);
const hydrate = selector.hydrate === true;

const canonical = {
  gw_action: req.gw_action ?? "artifact.list",
  gw_workspace_id: req.gw_workspace_id ?? null,

  // Flattened for easier access downstream
  artifact_type,
  parent_artifact_id,
  limit,
  offset,
  hydrate,
  tags_any: tags_any_raw,

  // Preserve selector (unchanged)
  selector,

  // Optional: receipts for deterministic tests / debugging
  meta: {
    requested_limit,
    applied_limit,
    was_clamped,
    default_limit: DEFAULT_LIMIT,
    max_limit: MAX_LIMIT,
  },
};

// Debug context
canonical._gw_debug = {
  received_shape: body ? "body" : "flat",
  operation: "list",
  hydrate_requested: hydrate,
  artifact_type_source:
    selectorArtifactType !== "" ? "selector.artifact_type"
    : topLevelArtifactType !== "" ? "top_level.artifact_type"
    : "empty",
};

return [{ json: canonical }];

// NQxb_Artifact_List_v1__Validate_Request
// Purpose: Validate required fields + enforce deterministic window cap + establish paging anchor (as_of).
// KGB rules:
// - No silent empty outputs
// - Deterministic pagination (within fetch cap)
// - Stable paging across multiple calls via selector.as_of (created_at <= as_of)
//
// Policy update (Option 2A Clamp):
// - Do NOT reject solely because limit > max.
// - Normalize_Request is the enforcement point (default + clamp).
// - Validate_Request confirms shape/sanity + enforces deterministic window cap.

const j = $json ?? {};

const gw_workspace_id = j.gw_workspace_id ?? null;
const artifact_type = j.artifact_type ?? null;

const selector_in =
  (j.selector && typeof j.selector === "object" && !Array.isArray(j.selector))
    ? j.selector
    : {};

const limit_in = selector_in.limit ?? j.limit ?? 50;
const offset_in = selector_in.offset ?? j.offset ?? 0;
const hydrate_in = selector_in.hydrate ?? j.hydrate ?? false;
const include_fields_in = selector_in.include_fields ?? j.include_fields ?? null;
const as_of_in = selector_in.as_of ?? j.as_of ?? null;

// BUG-011: Extract tags_any from flattened or selector.filters
const filters_obj = (selector_in.filters && typeof selector_in.filters === "object") ? selector_in.filters : {};
const tags_any_in = j.tags_any ?? filters_obj.tags_any ?? filters_obj.tags ?? null;

const toInt = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : NaN;
};

const limit = toInt(limit_in);
const offset = toInt(offset_in);

// ---- required: workspace ----
if (!gw_workspace_id || String(gw_workspace_id).trim() === "") {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "VALIDATION_ERROR",
        message: "gw_workspace_id is required for artifact.list operation",
        details: { missing_field: "gw_workspace_id", received_value: gw_workspace_id },
      },
    },
  }];
}

// ---- required: artifact_type ----
if (!artifact_type || String(artifact_type).trim() === "") {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "VALIDATION_ERROR",
        message: "artifact_type is required for artifact.list operation",
        details: { missing_field: "artifact_type", received_value: artifact_type },
      },
    },
  }];
}

// ---- selector numeric sanity ----
if (!Number.isFinite(limit) || !Number.isFinite(offset)) {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "VALIDATION_ERROR",
        message: "selector.limit and selector.offset must be numeric",
        details: { received_limit: limit_in, received_offset: offset_in },
      },
    },
  }];
}

// NOTE: limit upper-bound is enforced upstream (Normalize_Request) via clamp.
// Here we only ensure it's positive.
if (limit < 1) {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "VALIDATION_ERROR",
        message: "selector.limit must be >= 1",
        details: { received_limit: limit },
      },
    },
  }];
}

if (offset < 0) {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "VALIDATION_ERROR",
        message: "selector.offset must be >= 0",
        details: { received_offset: offset },
      },
    },
  }];
}

// ---- BUG-011: tags_any validation ----
let tags_any_validated = null;
if (tags_any_in !== null && tags_any_in !== undefined) {
  if (!Array.isArray(tags_any_in)) {
    return [{
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "selector.filters.tags_any must be an array of strings",
          details: { received_type: typeof tags_any_in, received_value: tags_any_in },
        },
      },
    }];
  }
  // Normalize: trim, lowercase, dedupe, filter empty
  const seen = new Set();
  tags_any_validated = tags_any_in
    .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
    .filter(t => t !== "" && !seen.has(t) && seen.add(t));
  if (tags_any_validated.length === 0) tags_any_validated = null;
}

// ---- deterministic window cap ----
// IMPORTANT: FETCH_CAP must be >= max_limit (+1 for has_more).
// Keep this as an internal deterministic safety window, independent of client limit.
const FETCH_CAP = 500;
const endExclusive = offset + limit + 1; // +1 supports meta.has_more truthfully

if (endExclusive > FETCH_CAP) {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      error: {
        code: "PAGINATION_WINDOW_EXCEEDED",
        message: `Requested pagination window exceeds deterministic cap (${FETCH_CAP}). Reduce offset/limit.`,
        details: { fetch_cap: FETCH_CAP, requested_offset: offset, requested_limit: limit },
      },
    },
  }];
}

// ---- paging anchor (as_of) ----
// If not provided, establish it once per request (client must pass it back for subsequent pages)
let as_of = null;
if (as_of_in && typeof as_of_in === "string" && as_of_in.trim() !== "") {
  const t = Date.parse(as_of_in);
  if (!Number.isFinite(t)) {
    return [{
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "VALIDATION_ERROR",
          message: "selector.as_of must be a valid ISO datetime string",
          details: { received_as_of: as_of_in },
        },
      },
    }];
  }
  as_of = new Date(t).toISOString();
} else {
  as_of = new Date().toISOString();
}

// Build a resolved selector we will carry forward
const selector_resolved = {
  ...selector_in,
  limit,
  offset,
  hydrate: hydrate_in === true,
  as_of,
};

if (Array.isArray(include_fields_in)) selector_resolved.include_fields = include_fields_in;
if (tags_any_validated) {
  const existingFilters = (selector_resolved.filters && typeof selector_resolved.filters === "object") ? selector_resolved.filters : {};
  selector_resolved.filters = { ...existingFilters, tags_any: tags_any_validated };
}

return [{
  json: {
    ...j,
    gw_workspace_id,
    artifact_type,
    selector: selector_resolved,
    limit,
    offset,
    hydrate: selector_resolved.hydrate,
    as_of,
    tags_any: tags_any_validated,
  },
}];

// NQxb_Artifact_List_v1__Build_PostgREST_Request
// BUG-001 FIX: Build PostgREST URL with proper ORDER BY, OFFSET, LIMIT
// This replaces the broken Supabase "Get many rows" node
//
// PostgREST query structure:
// - workspace_id=eq.{uuid}
// - artifact_type=eq.{type}
// - deleted_at=is.null
// - created_at=lte.{as_of}
// - order=created_at.desc,artifact_id.desc
// - limit={limit+1}  (for has_more detection)
// - offset={offset}

// NOTE: n8n sandbox disallows Node core modules (e.g., require('url')).
// So we build the query string manually (encodeURIComponent) instead of URLSearchParams.

const j = $json ?? {};

const workspace_id = j.gw_workspace_id;
const artifact_type = j.artifact_type;
const limit = j.limit ?? 50;
const offset = j.offset ?? 0;
const as_of = j.as_of ?? new Date().toISOString();
const parent_artifact_id = j.parent_artifact_id ?? null;

// BUG-011: Extract tags_any filter
const tags_any = Array.isArray(j.tags_any) ? j.tags_any : null;

// --- Safe query builder (no URLSearchParams / no require) ---
const esc = (v) => encodeURIComponent(String(v));
const pairs = [];

// Filters
pairs.push(`workspace_id=${esc(`eq.${workspace_id}`)}`);
pairs.push(`artifact_type=${esc(`eq.${artifact_type}`)}`);
pairs.push(`deleted_at=${esc('is.null')}`);
pairs.push(`created_at=${esc(`lte.${as_of}`)}`);

// Optional parent filter
if (parent_artifact_id) {
  pairs.push(`parent_artifact_id=${esc(`eq.${parent_artifact_id}`)}`);
}

// BUG-011: Optional tags_any filter (JSONB array contains)
// PostgREST: tags=cs.["tag1"] means tags array contains this subset
// For "any of" semantics, we check if tags contains ANY of the requested tags
if (tags_any && tags_any.length > 0) {
  const tagsJson = JSON.stringify(tags_any);
  pairs.push(`tags=${esc(`cs.${tagsJson}`)}`);
}

// Deterministic ordering (critical for pagination)
pairs.push(`order=${esc('created_at.desc,artifact_id.desc')}`);

// Pagination: fetch limit+1 for has_more detection
pairs.push(`limit=${esc(limit + 1)}`);
pairs.push(`offset=${esc(offset)}`);

const queryString = pairs.join('&');
// --- end safe query builder ---

return [{
  json: {
    ...j,
    _postgrest: {
      path: `/rest/v1/qxb_artifact?${queryString}`,
      method: 'GET',
      limit_requested: limit,
      offset_requested: offset,
      as_of_used: as_of,
    }
  }
}];

// NQxb_Artifact_List_v1__Apply_Filters_And_Pagination
// BUG-001 FIX: Simplified - ordering and offset now handled at DB level
//
// Purpose:
// - DE-DUPE (safety)
// - Compute has_more from limit+1 fetch
// - Package into _page_items + _meta
//
// NOTE: ORDER BY and OFFSET are now enforced by PostgREST.
// This node only needs to handle has_more detection and output formatting.

const req = $node["NQxb_Artifact_List_v1__Validate_Request"]?.json ?? {};
const postgrest = $node["NQxb_Artifact_List_v1__Build_PostgREST_Request"]?.json?._postgrest ?? {};

const selector = (req.selector && typeof req.selector === "object") ? req.selector : {};

const limit = postgrest.limit_requested ?? Number(selector.limit ?? 50);
const offset = postgrest.offset_requested ?? Number(selector.offset ?? 0);
const as_of = postgrest.as_of_used ?? selector.as_of ?? req.as_of ?? null;

// Gather rows from HTTP Request response
// HTTP Request returns array directly or wrapped
let rows = [];
const allItems = $input.all();

for (const item of allItems) {
  const data = item.json;
  if (Array.isArray(data)) {
    // Response was array at root
    rows.push(...data);
  } else if (data && typeof data === 'object') {
    // Single object or wrapped
    rows.push(data);
  }
}

// DE-DUPE by artifact_id (safety - shouldn't be needed with proper DB query)
const seen = new Set();
rows = rows.filter(r => {
  const id = (r?.artifact_id ?? "").toString();
  if (!id) return false;
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

// has_more computation:
// PostgREST fetched (limit + 1), so if we have > limit rows, there's more
let has_more = false;
let page = rows;

if (Number.isFinite(limit) && limit > 0) {
  if (rows.length > limit) {
    has_more = true;
    page = rows.slice(0, limit);
  } else {
    has_more = false;
    page = rows;
  }
} else {
  has_more = false;
  page = rows;
}

return [{
  json: {
    _page_items: page,
    _meta: {
      count: page.length,
      limit: Number.isFinite(limit) ? limit : null,
      offset: Number.isFinite(offset) ? offset : null,
      has_more,
      as_of: as_of ?? new Date().toISOString(),
