        ...extRaw,
        _merge_error: "No matching spine found",
        _searched_artifact_id: artifact_id,
      }
    });
    continue;
  }

  // Extract extension fields, stripping duplicates and lifecycle_stage
  const {
    artifact_id: _aid,
    artifact_type: _atype,
    created_at: _cat,
    updated_at: _uat,
    lifecycle_stage, // strip to prevent dual-lifecycle ambiguity
    ...extFields
  } = extRaw;

  // Merge: spine first, then extension overlays
  const merged = {
    ...spine,
    ...extFields,
