  gw_action: req.gw_action ?? "artifact.list",
  gw_workspace_id: req.gw_workspace_id ?? req.workspace_id ?? null,
  artifact_type: req.artifact_type ?? null,
  selector,
  data: { artifacts: cleanedArtifacts },
  meta: {
    count: Number.isInteger(meta_in.count) ? meta_in.count : cleanedArtifacts.length,
    limit: Number.isInteger(meta_in.limit) ? meta_in.limit : (selector.limit ?? null),
    offset: Number.isInteger(meta_in.offset) ? meta_in.offset : (selector.offset ?? null),
    has_more: meta_in.has_more === true,
    as_of: meta_in.as_of ?? selector.as_of ?? null,
  },
  timestamp: new Date().toISOString(),
};

return [{ json: response }];

// NQxb_Artifact_List_v1__Merge_Instruction_Pack
// v26 FIX: Process ALL items at once to avoid per-item execution issues

// Get ALL extension items from DB_Get
const allExtItems = $input.all();

// Get ALL spine items from Split Out
const allSpineItems = $items("Split Out");

// Build a map of spine by artifact_id for fast lookup
const spineById = new Map();
for (const item of allSpineItems) {
  const id = item.json?.artifact_id;
  if (id) spineById.set(id, item.json);
}

// Heuristic to detect extension row
const looksLikeExtRow = (o) =>
  o &&
  typeof o === "object" &&
  "artifact_id" in o &&
  "scope" in o &&
  "active" in o &&
  ("pack_format" in o || "priority" in o) &&
  !("artifact_type" in o) &&
  !("title" in o);

// Process each extension and merge with its spine
const results = [];

for (const extItem of allExtItems) {
  const extRaw = extItem.json ?? {};
  const artifact_id = extRaw.artifact_id;

  // Find matching spine
  const spine = spineById.get(artifact_id) ?? {};

  if (!spine.artifact_id) {
    results.push({
      json: {
        ...extRaw,
        _merge_error: "No matching spine found",
        _searched_artifact_id: artifact_id,
      }
    });
    continue;
  }

  // Build extension object
  let extension = null;
  if (looksLikeExtRow(extRaw)) {
    const {
      artifact_type, title, summary, tags, content,
      parent_artifact_id, version, deleted_at,
      owner_user_id, workspace_id,
      created_at, updated_at,
      ...rest
    } = extRaw;
    extension = Object.keys(rest).length ? rest : null;
  }

  // Merge: spine + extension nested
  const merged = {
    ...spine,
    extension,
  };

  results.push({ json: merged });
}

return results;

// Phase 2B Walk: Spine-only list merge for branch/leaf (no extension table)
// Returns spine items with extension: null for shape symmetry with Query.
// Shared by branch and leaf — both are spine-only types.
const items = ($json._page_items || []);
return items.map(item => ({ json: { ...item, extension: null } }));

// NQxb_Artifact_List_v1__Merge_Limb
// Phase 2B Walk: Merge spine + limb extension for list hydration.
// Shell table: artifact_id, created_at, updated_at.
// Only artifact_id stripped; created_at/updated_at preserved in extension.

const allExtItems = $input.all();
const allSpineItems = $items("NQxb_Artifact_List_v1__Explode_Limb_Page");

const spineById = new Map();
for (const item of allSpineItems) {
  const id = item.json?.artifact_id;
  if (id) spineById.set(id, item.json);
}

const results = [];

for (const extItem of allExtItems) {
  const extRaw = extItem.json ?? {};
  const artifact_id = extRaw.artifact_id;

  const spine = spineById.get(artifact_id) ?? {};

  if (!spine.artifact_id) {
    results.push({
      json: {
        ...extRaw,
        _merge_error: "No matching spine found",
        _searched_artifact_id: artifact_id,
      }
    });
    continue;
  }

  const { artifact_id: _aid, ...rest } = extRaw;
  const extension = Object.keys(rest).length ? rest : null;

  results.push({ json: { ...spine, extension } });
}

return results;
